import React, { useEffect, useState } from 'react';
import './CommandeListe.css';

function CommandeList() {
  const [commandes, setCommandes] = useState([]);

  useEffect(() => {
    fetch('http://localhost:3001/commandes')
      .then(res => res.json())
      .then(data => setCommandes(data))
      .catch(err => console.error('Erreur chargement commandes:', err));
  }, []);

  return (
    <div>
      <h2>Liste des Commandes</h2>
      <table>
        <thead>
          <tr>
            <th>ID</th>
            <th>Client</th>
            <th>Article</th>
            <th>Date</th>
            <th>Quantité</th>
          </tr>
        </thead>
        <tbody>
          {commandes.map(cmd => (
            <tr key={cmd.idCOM}>
              <td>{cmd.idCOM}</td>
              <td>{cmd.nomCli}</td>
              <td>{cmd.nomArt}</td>
              <td>{cmd.dateCom}</td>
              <td>{cmd.QteCom}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default CommandeList;
